sql:
SELECT strategy_description, strategy_status
FROM mitigation_strategies
WHERE strategy_id = 1;

SELECT SUM(impact_severity) 
FROM risk_impact_analysis 
WHERE risk_id = 3;

SELECT risk_level 
FROM risk_metrics 
WHERE risk_id = 3;

SELECT * 
FROM mitigation_strategies
WHERE risk_id = 2;

SELECT report_summary
FROM risk_reports
WHERE report_id = 1;

external_knowledge:
- "stormy clouds" refers to risks;
- "brewing" implies the mitigation status is "In Progress";
- "dark skies" and "reach above the horizon" represent the severity of the risks being greater than 5;
- "winds" signify the exploitability;
- "shadows stretch across multiple landscapes" indicates there are more than one impact descriptions;
- "under a watchful eye with plans either drawn up or signed off" means the strategy status is either "Proposed" or "Approved".

sql:
SELECT *
FROM risk_impact_analysis
WHERE impact_description LIKE '%Network%' AND impact_severity > 5;

SELECT r.report_id, r.risk_id, r.user_id, u.user_name, u.role, r.report_date, r.report_title, r.report_status
FROM risk_reports r
INNER JOIN users u ON r.user_id = u.user_id;

SELECT SUM(severity) AS total_severity
FROM risk_metrics
WHERE risk_level = 'High';

SELECT category_name, category_weight, parent_category_id
FROM risk_categories
WHERE category_weight > 3;

SELECT category_name, category_weight
FROM risk_categories
WHERE category_weight = (SELECT MAX(category_weight) FROM risk_categories);

SELECT user_id, COUNT(report_id) AS report_count
FROM risk_reports
GROUP BY user_id;

SELECT risk_level 
FROM risk_metrics 
WHERE risk_id IN (
    SELECT risk_id 
    FROM mitigation_strategies
) 
AND risk_id IN (
    SELECT risk_id 
    FROM risk_impact_analysis
);

SELECT user_id, user_name, email, role, phone_number, last_login, user_status
FROM users
WHERE user_id IN (SELECT DISTINCT user_id FROM risk_reports);

SELECT metric_id, risk_id, severity
FROM risk_metrics
WHERE risk_level = 'High' AND severity > (SELECT AVG(severity) FROM risk_metrics);

SELECT MAX(severity) AS highest_severity, COUNT(DISTINCT risk_id) AS total_high_risk_items
FROM risk_metrics
WHERE risk_level = 'High';

external_knowledge:
- 'serious risks' refers to risks with a high level of risk; 
- 'successfully addressed' means the mitigation status is completed; 
- 'moderate to high severity rating' refers to a severity level between 5 and 10.
